     1→import { create } from 'zustand';
     2→import { persist } from 'zustand/middleware';
     3→import type { TimeEntry, TimeTrackingProject, EntryFilters, TimeViewMode, TimeTrackingState } from '../types';
     4→import { timeTrackingDb } from '../db/timeTrackingDb';
     5→
     6→interface TimeTrackingStore extends TimeTrackingState {
     7→  // ==================== TIMER ACTIONS ====================
     8→
     9→  /**
    10→   * Start a new timer
    11→   */
    12→  startTimer: (description: string, projectId?: string, taskId?: string) => void;
    13→
    14→  /**
    15→   * Stop the currently running timer
    16→   */
    17→  stopTimer: () => Promise<void>;
    18→
    19→  /**
    20→   * Update the active timer (e.g., change description or project)
    21→   */
    22→  updateActiveEntry: (updates: Partial<TimeEntry>) => void;
    23→
    24→  // ==================== ENTRY ACTIONS ====================
    25→
    26→  /**
    27→   * Add a manual time entry (retroactive logging)
    28→   */
    29→  addManualEntry: (entry: Omit<TimeEntry, 'id' | 'createdAt' | 'updatedAt' | 'workspaceId'>) => Promise<void>;
    30→
    31→  /**
    32→   * Update an existing time entry
    33→   */
    34→  updateEntry: (id: string, updates: Partial<TimeEntry>) => Promise<void>;
    35→
    36→  /**
    37→   * Delete a time entry
    38→   */
    39→  deleteEntry: (id: string) => Promise<void>;
    40→
    41→  /**
    42→   * Duplicate a time entry (for quick re-entry)
    43→   */
    44→  duplicateEntry: (id: string) => Promise<void>;
    45→
    46→  /**
    47→   * Continue from a previous entry (start new timer with same details)
    48→   */
    49→  continueEntry: (id: string) => void;
    50→
    51→  // ==================== PROJECT ACTIONS ====================
    52→
    53→  /**
    54→   * Add a new project
    55→   */
    56→  addProject: (project: Omit<TimeTrackingProject, 'id' | 'createdAt' | 'updatedAt'>) => Promise<void>;
    57→
    58→  /**
    59→   * Update an existing project
    60→   */
    61→  updateProject: (id: string, updates: Partial<TimeTrackingProject>) => Promise<void>;
    62→
    63→  /**
    64→   * Delete a project (and all its entries)
    65→   */
    66→  deleteProject: (id: string) => Promise<void>;
    67→
    68→  /**
    69→   * Archive a project
    70→   */
    71→  archiveProject: (id: string) => Promise<void>;
    72→
    73→  /**
    74→   * Unarchive a project
    75→   */
    76→  unarchiveProject: (id: string) => Promise<void>;
    77→
    78→  // ==================== QUERY ACTIONS ====================
    79→
    80→  /**
    81→   * Load entries from database with optional filters
    82→   */
    83→  loadEntries: (filters?: EntryFilters) => Promise<void>;
    84→
    85→  /**
    86→   * Load projects from database
    87→   */
    88→  loadProjects: () => Promise<void>;
    89→
    90→  /**
    91→   * Get entries by date range
    92→   */
    93→  getEntriesByDateRange: (start: Date, end: Date) => TimeEntry[];
    94→
    95→  /**
    96→   * Get entries by project
    97→   */
    98→  getEntriesByProject: (projectId: string) => TimeEntry[];
    99→
   100→  // ==================== FILTER ACTIONS ====================
   101→
   102→  /**
   103→   * Set filters for entry list
   104→   */
   105→  setFilters: (filters: Partial<EntryFilters>) => void;
   106→
   107→  /**
   108→   * Clear all filters
   109→   */
   110→  clearFilters: () => void;
   111→
   112→  /**
   113→   * Set view mode
   114→   */
   115→  setViewMode: (mode: TimeViewMode) => void;
   116→
   117→  // ==================== UTILITY ACTIONS ====================
   118→
   119→  /**
   120→   * Get total time tracked for current filters
   121→   */
   122→  getTotalTime: () => number;
   123→
   124→  /**
   125→   * Get time tracked by project (for reports)
   126→   */
   127→  getTimeByProject: () => Record<string, number>;
   128→
   129→  // ==================== PHASE A: KANBAN INTEGRATION ====================
   130→
   131→  /**
   132→   * Get all time entries for a specific Kanban card
   133→   */
   134→  getEntriesForCard: (cardId: string) => TimeEntry[];
   135→
   136→  /**
   137→   * Get total time logged for a specific Kanban card (in seconds)
   138→   */
   139→  getTotalTimeForCard: (cardId: string) => number;
   140→
   141→  /**
   142→   * Start timer for a specific Kanban card
   143→   */
   144→  startTimerForCard: (cardId: string, taskName: string) => void;
   145→}
   146→
   147→const DEFAULT_WORKSPACE_ID = 'default';
   148→
   149→export const useTimeTrackingStore = create<TimeTrackingStore>()(
   150→  persist(
   151→    (set, get) => ({
   152→      // ==================== INITIAL STATE ====================
   153→      activeEntry: null,
   154→      entries: [],
   155→      projects: [],
   156→      selectedDate: new Date().toISOString().split('T')[0],
   157→      selectedProject: null,
   158→      selectedTags: [],
   159→      viewMode: 'list',
   160→      filters: {
   161→        dateRange: 'last7days',
   162→        projectIds: [],
   163→        tags: [],
   164→        searchQuery: ''
   165→      },
   166→      reminderEnabled: false,
   167→      idleDetectionMinutes: 0,
   168→      roundingMinutes: 0,
   169→
   170→      // ==================== TIMER ACTIONS ====================
   171→
   172→      startTimer: (description, projectId, taskId) => {
   173→        const entry: TimeEntry = {
   174→          id: crypto.randomUUID(),
   175→          workspaceId: DEFAULT_WORKSPACE_ID,
   176→          description,
   177→          projectId,
   178→          taskId,
   179→          startTime: new Date().toISOString(),
   180→          duration: 0,
   181→          billable: false,
   182→          tags: [],
   183→          createdAt: new Date().toISOString(),
   184→          updatedAt: new Date().toISOString()
   185→        };
   186→
   187→        set({ activeEntry: entry });
   188→
   189→        // Save to localStorage for persistence (backup)
   190→        localStorage.setItem('activeTimer', JSON.stringify(entry));
   191→      },
   192→
   193→      stopTimer: async () => {
   194→        const { activeEntry, entries } = get();
   195→        if (!activeEntry) return;
   196→
   197→        const endTime = new Date().toISOString();
   198→        const duration = Math.floor(
   199→          (new Date(endTime).getTime() - new Date(activeEntry.startTime).getTime()) / 1000
   200→        );
   201→
   202→        const completedEntry: TimeEntry = {
   203→          ...activeEntry,
   204→          endTime,
   205→          duration,
   206→          updatedAt: new Date().toISOString()
   207→        };
   208→
   209→        // Save to IndexedDB
   210→        await timeTrackingDb.addEntry(completedEntry);
   211→
   212→        // Update state
   213→        set({
   214→          activeEntry: null,
   215→          entries: [completedEntry, ...entries]
   216→        });
   217→
   218→        // Clear localStorage backup
   219→        localStorage.removeItem('activeTimer');
   220→      },
   221→
   222→      updateActiveEntry: (updates) => {
   223→        const { activeEntry } = get();
   224→        if (!activeEntry) return;
   225→
   226→        const updatedEntry = {
   227→          ...activeEntry,
   228→          ...updates,
   229→          updatedAt: new Date().toISOString()
   230→        };
   231→
   232→        set({ activeEntry: updatedEntry });
   233→
   234→        // Update localStorage backup
   235→        localStorage.setItem('activeTimer', JSON.stringify(updatedEntry));
   236→      },
   237→
   238→      // ==================== ENTRY ACTIONS ====================
   239→
   240→      addManualEntry: async (entryData) => {
   241→        const { entries } = get();
   242→
   243→        const entry: TimeEntry = {
   244→          ...entryData,
   245→          id: crypto.randomUUID(),
   246→          workspaceId: DEFAULT_WORKSPACE_ID,
   247→          createdAt: new Date().toISOString(),
   248→          updatedAt: new Date().toISOString()
   249→        };
   250→
   251→        // Save to IndexedDB
   252→        await timeTrackingDb.addEntry(entry);
   253→
   254→        // Update state
   255→        set({ entries: [entry, ...entries] });
   256→      },
   257→
   258→      updateEntry: async (id, updates) => {
   259→        const { entries } = get();
   260→
   261→        // Update in IndexedDB
